class ChatBot:
    def __init__(self, name):
        self.name = name
        self.rules = {
            "hello": "Hey! I'm " + name + ", your friendly bot.",
            "how are you": "I'm running at 100% — thanks for asking!",
            "help": "I can chat about jokes, weather, or just say hi!",
            "joke": "Why did the computer go to the doctor? It had a virus! 🤖",
            "bye": "Goodbye! Come back and chat anytime."
        }

    def reply(self, message):
        message = message.lower()
        for keyword, response in self.rules.items():
            if keyword in message:
                return response
        return "I'm still learning — I don't know that one yet!"


bot = ChatBot("PyBot")
conversation = ["Hello!", "how are you?", "tell me a joke", "bye"]

for msg in conversation:
    print("You:", msg)
    print(bot.name + ":", bot.reply(msg))
    print("")
